    course_description,
    class_attributes,
    enrollment_requirements
) VALUES
    ('INFO-I 514', 'SEMINAR ON TECH FOR ANIMALS', '10050', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:15 PM', 'I 107', 'Christena Nippert-Eng', 21, NULL, 'Seminar', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This exploratory seminar is an introduction to ACI. We will draw on faculty and student selected readings, multimedia materials, and guest lectures from current ACI practitioners to see what we think about the ethics, history, state-of-the art, and possible futures for this broad field of practice.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 519', 'INTRODUCTION TO BIOINFORMATICS', '4139', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 344', 'Volker Brendel', 19, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Sequence alignment and assembly; RNA structure, protein and molecular modeling; genomics and proteomics; gene prediction; phylogenetic analysis; information and machine learning; visual and graphical analysis bioinformatics; worldwide biologic databases; experimental design and data collection techniques; scientific and statistical data analysis; database and data mining methods; and network and Internet methods.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 519', 'INTRODUCTION TO BIOINFORMATICS', '4140', 'Class Status', 'F Friday 9:45 AM–11:00 AM', 'LH 101', 'Staff', 19, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Sequence alignment and assembly; RNA structure, protein and molecular modeling; genomics and proteomics; gene prediction; phylogenetic analysis; information and machine learning; visual and graphical analysis bioinformatics; worldwide biologic databases; experimental design and data collection techniques; scientific and statistical data analysis; database and data mining methods; and network and Internet methods.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 520', 'SECURITY FOR NETWORKED SYSTEMS', '9455', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WY 005', 'Yan Huang', 10, 'Lecture', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 520', 'SECURITY FOR NETWORKED SYSTEMS', '10062', 'Class Status', 'F Friday 11:30 AM–12:20 PM', 'IF 3115', 'Yan Huang', 6, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 520', 'SECURITY FOR NETWORKED SYSTEMS', '10753', 'Class Status', 'F Friday 12:40 PM–1:30 PM', 'IF 3115', 'Yan Huang', 2, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 520', 'SECURITY FOR NETWORKED SYSTEMS', '14702', 'Class Status', 'F Friday 1:50 PM–2:40 PM', 'IF 3115', 'Yan Huang', 2, 'Laboratory', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 520', 'SECURITY FOR NETWORKED SYSTEMS', '7525', 'Class Status', NULL, 'OL ONLINE', 'Yan Huang', 5, 'Lecture', 'Lecture', '3', 'WYLIE HALL', ARRAY[]::TEXT[], 'This course is an extensive survey of system and network security. Course materials cover the threats to information confidentiality, integrity and availability and the defense mechanisms that control such threats. The course provides the foundation for more advanced security courses and hands-on experiences through course projects.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 529', 'MACHINE LEARNING BIOINFORMATCS', '12650', 'Class Status', NULL, 'WB WEB', 'Chhavi Thakur', 17, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course covers advanced topics in Bioinformatics with a focus on machine learning. The course will review existing techniques such as hidden Markov models, artificial neural network, decision trees, stochastic grammars, and kernel methods. Examine application of these techniques to current bioinformatics problems including: genome annotation and comparison, gene finding, RNA secondary structure prediction, protein structure prediction, gene expression analysis, proteomics, and integrative functional genomics.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 535', 'MANAGEMENT, ACCESS, AND USE OF BIG AND COMPLEX DATA', '9021', 'Closed', 'Thirteen Week', 'WB WEB', 'Inna Kouper', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Innovation today is emerging from a preponderance of data from sensors, social media, and the Internet. This course covers knowledge representation, data process, and data management for big and complex data. Specific topics include data integration, semantics, and provenance; workflows and pipelines; and distributed noSQL stores.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 540', 'HUMAN ROBOT INTERACTION', '9398', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'I E130', 'Selma Sabanovic', 3, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course surveys the field of human-robot interaction (HRI), which involves understanding how people perceive and respond to robots and creating robots that interact naturally with people. We will discuss the design, evaluation and societal significance of interactive robots from a human-centered perspective through readings, discussion and developing HRI prototypes.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 541', 'INTRODUCTION TO HCI/D', '14711', 'Class Status', 'MW Monday, Wednesday 2:15 PM–4:45 PM', 'TE F160', 'Colin Gray', 43, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'Human-Computer Interaction Design refers to designing interactive products, services, and experiences. This course offers a holistic and practice-oriented introduction to the field. Working individually and in teams, students will take on an authentic design problem and follow a creative process to achieve design outcomes.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 542', 'FOUNDATIONS OF HCI', '13470', 'Class Status', 'Tu Tuesday 5:45 PM–8:15 PM', 'LU 1001', 'Eli Blevis', 11, NULL, 'Lecture', '3', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], '"Foundations of HCI" offers a survey overview of the field of Human-Computer Interaction Design. It introduces the main themes of HCI set generally in a historical context. Themes include interaction design, cognitive modeling, distributed cognition, computer-supported cooperative work, data visualization, ubiquitous computing, affective computing, and domestic computing, among others.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 544', 'EXPERIENCE DESIGN', '8361', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'I E150', 'Elizabeth Kaziunas', 10, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Accompanying its move from workplace productivity into culture-at-large, HCI is increasingly concerned with designing engaging user experiences. "Experience Design" is an interdisciplinary course that brings anthropological, philosophical, design, and technological perspectives together to explore novel ways to research, design, and evaluate qualities of user experience.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 547', 'MUSIC INFORMATION PROCESSING: AUDIO', '14704', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'I 321A', 'Christopher Raphael', 17, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'This course deals with various music analysis and processing problems that use sampled audio as the primary data representation. Discusses digital signal processing, including filtering and its relationship to Fourier techniques. Topics include synthesis, effects processing, score following, blind music recognitions, and accompaniment systems.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 552', 'INDEPENDENT STUDY IN BIOINFORMATICS', '6135', 'Class Status', NULL, NULL, 'Yijie Wang', 6, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research under the direction of a faculty member culminating in a written report.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 552', 'INDEPENDENT STUDY IN BIOINFORMATICS', '6136', 'Class Status', NULL, NULL, 'Yijie Wang', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research under the direction of a faculty member culminating in a written report.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 554', 'INDEPENDENT STUDY IN HUMAN COMPUTER INTERACTION', '2039', 'Class Status', NULL, NULL, 'Colin Gray', 17, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research under the direction of a faculty member, culminating in a written report.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 554', 'INDEPENDENT STUDY IN HUMAN COMPUTER INTERACTION', '4493', 'Class Status', NULL, NULL, 'Colin Gray', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent readings and research under the direction of a faculty member, culminating in a written report.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 587', 'INTRODUCTION TO VIRTUAL HERITAGE', '9769', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:30 PM', 'IF 1019', 'Gabriele Guidi', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course focuses on how digital technology can represent, restore, disseminate, and help with analysis of artifacts such as vases, furniture, sculpture, monuments, and buildings. Other topics covered include the history and methodologies of Virtual Heritage. Each semester a different case study will provide the focus for the course.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 590', 'TOPICS IN INFORMATICS', '5691', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'LH 130', 'Goren Gordon', 33, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Variable topic. Emphasis is on new developments and research in informatics.', ARRAY[]::TEXT[], NULL),
