    ('INFO-I 591', 'GRADUATE INTERNSHIP', '5072', 'Class Status', NULL, NULL, 'Gabriele Guidi, Colin Gray', 8, NULL, 'Internship', '0–6', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics course work.', ARRAY[]::TEXT[], NULL),
