    ('INFO-I 591', 'GRADUATE INTERNSHIP', '14692', 'Closed', NULL, NULL, 'Apu Kapadia', 0, NULL, 'Internship', '0–6', NULL, ARRAY[]::TEXT[], 'Students gain professional work experience in an industry or research organization setting, using skills and knowledge acquired in informatics course work.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 601', 'INTRODUCTION TO COMPLEX SYSTEMS', '8059', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:55 AM', 'I 105', 'Alessandro Flammini', 3, NULL, 'Lecture', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'The course will cover fractals, emergent behavior, chaos theory, cooperative phenomena, and complex networks. Students will learn how to think differently about complex realities, finding ways to understand their complexity and addressing the problems they pose.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 609', 'ADVANCED SEMINAR I IN INFORMATICS', '10521', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:15 PM', 'I 107', 'Christena Nippert-Eng', 21, NULL, 'Seminar', '3', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Ph.D. student introduction to major historical and emerging theories, methods, technologies, and applications in Informatics. Provides students with opportunities to explore relevant research literature, results, and applications. Students will develop a profound understanding of leading research approaches and paradigms in their research area.', ARRAY[]::TEXT[], NULL),
