    ('INFO-I 617', 'INFORMATICS IN LIFE SCIENCES AND CHEMISTRY', '6292', 'Class Status', 'F Friday 9:45 AM–11:00 AM', 'LH 101', 'Staff', 19, 'Laboratory', 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('INFO-I 692', 'THESIS/PROJECT IN BIOINFORMATICS', '2040', 'Class Status', NULL, 'SI 030', 'Yijie Wang', 9, NULL, 'Research', '1–6', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'The student prepares and presents thesis or project in an area of bioinformatics. The product is substantial, typically a multi-chapter paper or carefully designed and evaluated application, based on well-planned research or scholarly project. Details are worked out between student and sponsoring faculty member.', ARRAY[]::TEXT[], NULL),
    ('INFO-I 698', 'RESEARCH IN INFORMATICS', '5308', 'Class Status', NULL, NULL, 'Gabriele Guidi', 9, NULL, 'Research', '1–12', NULL, ARRAY[]::TEXT[], 'Research, not dissertation-related, under the direction of a member of the graduate faculty.', ARRAY[]::TEXT[], NULL),
