    ('INFO-T 100', 'TOPICS IN INFORMATICS TECHNOLOGY', '14366', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'I 107', 'Maria Clor', 1, NULL, 'Lecture', '1.5', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Variable topic. The course serves as an introduction to a specific information technology in a hands-on setting. Emphasis is on problem solving techniques using technology.', ARRAY[]::TEXT[], NULL),
    ('INFO-T 100', 'TOPICS IN INFORMATICS TECHNOLOGY', '14933', 'Class Status', 'Th Thursday 11:10 AM–12:10 PM', 'GA 1106', 'Paul Macklin, Tiana Iruoje', 4, NULL, 'Lecture', '1.5', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Variable topic. The course serves as an introduction to a specific information technology in a hands-on setting. Emphasis is on problem solving techniques using technology.', ARRAY[]::TEXT[], NULL),
    ('INFO-T 100', 'TOPICS IN INFORMATICS TECHNOLOGY', '14365', 'Closed', 'MW Monday, Wednesday 12:45 PM–1:35 PM', 'LH 004', 'Mary Loveless', 0, NULL, 'Lecture', '1.5', 'MYLES BRAND HALL', ARRAY[]::TEXT[], 'Variable topic. The course serves as an introduction to a specific information technology in a hands-on setting. Emphasis is on problem solving techniques using technology.', ARRAY[]::TEXT[], NULL),
    ('INFO-T 110', '(MIS)INFORMATION LITERACY', '34948', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'FF 310', 'Taeyoung Lee', 2, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Disinformation, fake news, deceptive social bots, echo chambers, astroturf, troll factories, conspiracy theories, coordinated inauthentic influence campaigns: we experience these online manipulations every day, whether we know it or not. Acquire knowledge and skills in building media and information literacy and algorithmic countermeasures against social media abuse and its harms.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('INFO-Y 395', 'CAREER DEVELOPMENT FOR INFORMATICS MAJORS', '5186', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'LU 1001', 'Caitlyn Thompson', 8, NULL, 'Lecture', '1', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
    ('INFO-Y 395', 'CAREER DEVELOPMENT FOR INFORMATICS MAJORS', '5989', 'Class Status', 'M Monday 9:35 AM–10:50 AM', 'I E130', 'David Gregoire', 6, NULL, 'Lecture', '1', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
    ('INFO-Y 395', 'CAREER DEVELOPMENT FOR INFORMATICS MAJORS', '6374', 'Class Status', 'W Wednesday 9:35 AM–10:50 AM', 'I E130', 'Caitlyn Thompson', 3, NULL, 'Lecture', '1', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
    ('INFO-Y 395', 'CAREER DEVELOPMENT FOR INFORMATICS MAJORS', '5639', 'Closed', 'Tu Tuesday 9:35 AM–10:50 AM', 'LU 1001', 'Caitlyn Thompson', 0, NULL, 'Lecture', '1', 'LUDDY CENTER FOR AI', ARRAY[]::TEXT[], 'Develop skills and knowledge that enable you to successfully pursue your career search, both at the time of graduation and later as you progress through your career. The course covers techniques and strategies which make your job search more efficient and effective.', ARRAY[]::TEXT[], NULL),
    ('INST-B 100', 'ELEMENTARY BENGALI I', '14934', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 4:20 PM–5:10 PM', 'BH 010', 'Rebecca Manring, Nazia Masood', 4, NULL, 'Lecture', '5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Basic sound patterns and writing system with ideas about grammar. Ideas about simple sentence structure and basic grammar leading to reading and construction of short sentences. Learning essential vocabulary for everyday conversation. Practicing different expressions: apology, greeting, etc. Classroom use of films, tapes, short conversation, stories, etc.', ARRAY['IUB GenEd World Language class'], NULL),
    ('INST-B 300', 'ADVANCED BENGALI I', '14938', 'Class Status', 'TuWTh Tuesday, Wednesday, Thursday 4:20 PM–5:10 PM', 'WH 108', 'Rebecca Manring', 5, NULL, 'Practice', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Development of higher level linguistic functions in Bengali in the four skills of reading, writing, speaking and listening. Cultural literacy is enhanced through interaction with native speakers and the use of authentic media and literature. Culminates with a research paper in Bengali. Conducted entirely in Bengali.', ARRAY[]::TEXT[], NULL),
    ('INST-B 506', 'ELEMENTARY BENGALI I', '14935', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 4:20 PM–5:10 PM', 'BH 010', 'Rebecca Manring, Nazia Masood', 5, NULL, 'Seminar', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the Bengali language through its writing system and basic grammar. Graded exercises and readings leading to mastery of grammatical structures and essential vocabulary. Development of reading and writing competence and simple conversations in contemporary Bengali.', ARRAY[]::TEXT[], NULL),
    ('INST-B 510', 'ADVANCED BENGALI I', '14939', 'Class Status', 'TuWTh Tuesday, Wednesday, Thursday 4:20 PM–5:10 PM', 'WH 108', 'Rebecca Manring', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students will work at systematically developing higher level linguistic functions and cultural literacy. Class is conducted entirely in Bengali. Students will develop and support arguments, working with authentic materials in print, broadcast and film formats. Students will produce a research paper on a subject of their choosing (with instructor''s approval).', ARRAY[]::TEXT[], NULL),
    ('INST-H 100', 'ELEMENTARY HINDI I', '3311', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'BH 135', 'Rashmi Sharma', 5, NULL, 'Lecture', '5', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the Hindi language, the writing system, and basic grammar. Graded exercises and readings leading to mastery of grammatical structures and essential vocabulary. Development of reading and writing competence and simple conversations based on personal information, courtesy expressions, greetings in contemporary Hindi. Classroom use of stories, tapes, films, and songs.', ARRAY['IUB GenEd World Language class'], NULL),
    ('INST-H 110', 'HINDI SCRIPT', '37146', 'Class Status', 'Non Standard Session', 'WB WEB', 'Rebecca Manring', 6, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Hindi script for non-literate native speakers.', ARRAY[]::TEXT[], NULL),
    ('INST-H 200', 'INTERMEDIATE HINDI I', '15272', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 018', 'Rashmi Sharma', 4, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Reading mythology, folklore, modern short stories, essays and poetry, including several examples from Hindi literature. Students compose and perform dialogues based on the material read and the usage of role-playing cards.', ARRAY['IUB GenEd World Language class'], NULL),
    ('INST-H 300', 'ADVANCED HINDI I', '15273', 'Class Status', 'MWTh Monday, Wednesday, Thursday 9:10 AM–10:00 AM', 'JH A107', 'Rashmi Sharma', 9, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Development of higher level linguistic functions in Hindi in the four skills of reading, writing, speaking and listening. Cultural literacy is enhanced through interaction with native speakers and the use of authentic media and literature. Culminates with a research paper in Hindi. Conducted entirely in Hindi.', ARRAY[]::TEXT[], NULL),
    ('INST-H 506', 'ELEMENTARY HINDI I', '3092', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'BH 135', 'Rashmi Sharma', 5, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the Hindi language through its writing system and basic grammar. Graded exercises and readings leading to mastery of grammatical structures and essential vocabulary. Development of reading and writing competence and simple conversations in contemporary Hindi. Classroom use of story books, tapes, and films in Hindi.', ARRAY[]::TEXT[], NULL),
    ('INST-H 508', 'INTERMEDIATE HINDI I', '3207', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 018', 'Rashmi Sharma', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focuses on reading such literature as mythology, folklore, and modern short stories and poetry, including several examples from Urdu literature. Students compose and perform their own dialogues based on the material read.', ARRAY[]::TEXT[], NULL),
    ('INST-H 510', 'ADVANCED HINDI I', '12315', 'Class Status', 'MWTh Monday, Wednesday, Thursday 9:10 AM–10:00 AM', 'JH A107', 'Rashmi Sharma', 9, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Students will work at systematically developing higher level linguistic functions and cultural literacy. Class is conducted entirely in Hindi. Students will develop and support arguments, working with authentic materials in print, broadcast, and film formats. Students will produce a research paper on a subject of their choosing (with instructor''s approval).', ARRAY[]::TEXT[], NULL),
    ('INST-I 100', 'INTRODUCTION TO INDIA', '10890', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'TE F160', 'Gwendolyn Kirk', 12, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'Basic cultural literacy in India Studies through critical reading/lectures from India Studies faculty/film/discussion to discover what makes India the world power it is today, and why we need to know more about it, from its bloody birth in Partition to her ancient history and back to contemporary India.', ARRAY['IUB GenEd World Culture credit
COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('INST-I 656', 'GRADUATE READINGS IN INDIC STUDIES', '11601', 'Class Status', NULL, NULL, 'Rebecca Manring', 2, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Selected and substantive topics investigated from ancient, medieval, and modern texts about the civilization of India.', ARRAY[]::TEXT[], NULL),
