    ('INST-S 110', 'SANSKRIT FOR YOGA TEACHERS', '29842', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 123', 'Rebecca Manring', 12, NULL, 'Practice', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'History of Sanskrit and its script with emphasis on correct pronunciation.', ARRAY[]::TEXT[], NULL),
    ('INST-U 110', 'URDU SCRIPT', '33360', 'Class Status', 'Non Standard Session', 'WB WEB', 'Rebecca Manring', 6, NULL, 'Practice', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces students to the Nastaliq script, including pronunciation and intonation, basic conversation patterns, and the elements of spelling, reading, and writing in Urdu.', ARRAY[]::TEXT[], NULL),
    ('INST-U 200', 'INTERMEDIATE URDU I', '11017', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'ED 3284', 'Rebecca Manring, Anam Ikhtiar', 7, NULL, 'Lecture', '4', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Urdu short stories, essays, poetry (gazals), dramas, newspapers and magazine articles, etc., will be utilized for reading. Initiate basic communicative tasks related to daily activities and various situations.', ARRAY['IUB GenEd World Language class'], NULL),
