    ('INTL-I 315', 'RESEARCH DESIGN IN INTERNATIONAL STUDIES', '13655', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 009', 'Sarah Bauerle Danzman', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to research design and methodology used in international studies in preparation for undertaking research abroad and completing the I400 / I406 Capstone Seminar.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 340', 'ETHICS AND DECISION-MAKING IN INTERNATIONAL POLITICS', '34479', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 144', 'Nicole Hassoun', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Addresses the role of ethics and morality in the international system as applied to states, international organizations, nongovernmental organizations, and individuals. Explores dilemmas policymakers face as they weigh alternatives, try to reconcile competing demands, and search for acceptable trade-offs. Focuses on problems such as mass atrocities, forms of slavery, poverty, and the challenges of dealing with illiberal governments.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 346', 'WOMEN, GENDER, AND HUMAN RIGHTS MOVEMENTS', '29691', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0009', 'Kate Hunt', 25, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Explores the tools and strategies used by social movements focused on women''s and gender rights globally. Covers how international and domestic laws and contexts interact and influence these movements, as well as how such movements strategize within these circumstances.', ARRAY[]::TEXT[], NULL),
