    ('INTL-I 428', 'SOCIAL JUSTICE AND THE ENVIRONMENT', '10083', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 237', 'Andrea Siqueira', 2, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interdisciplinary study of comparative environmental justice issues around the world.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 429', 'GLOBAL HEALTH POLITICS', '29704', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0011', 'Lucía Stavig', 0, NULL, 'Seminar', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Study of global health policies and their relationships to social movements. Focuses on the effect of global governance institutions and NGOs on global health policy and action.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 434', 'INTERNATIONAL CLIMATE GOVERNANCE', '10298', 'Closed', 'Th Thursday 12:45 PM–3:15 PM', 'PV 270', 'Jessica O''Reilly', 0, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'Study of climate issues with a focus on the effect of global governance institutions and NGOs on climate policy and action. May include attendance at national and/or international climate conferences as part of official IU delegation.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 500', 'TOPICS IN GLOBAL STUDIES', '29706', 'Class Status', 'Tu Tuesday 3:00 PM–5:00 PM', 'HD TBA', 'Jessica Steinberg', 2, NULL, 'Seminar', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Explores a variety of world issues such as politics, religion, and globalization; urbanization, space, and development; and international security in the 21st century.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 502', 'SEMINAR IN GLOBAL HEALTH AND ENVIRONMENT', '29708', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'PV 273', 'Stephen Macekura', 3, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'Advanced seminar examining world health and environmental challenges, such as deforestation, climate change and infectious diseases. Focuses on the interaction of health and environmental problems crossing national borders and requiring multinational or global effort to solve.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 502', 'SEMINAR IN GLOBAL HEALTH AND ENVIRONMENT', '29709', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0011', 'Lucía Stavig', 0, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'Advanced seminar examining world health and environmental challenges, such as deforestation, climate change and infectious diseases. Focuses on the interaction of health and environmental problems crossing national borders and requiring multinational or global effort to solve.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 503', 'SEMINAR IN GLOBAL DEVELOPMENT', '15160', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 238', 'Hong Zhang', 0, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced seminar that focuses on the interaction between social, political, and economic forces and human development at global, national, and subnational scales; introduces theoretical perspectives on economic development and the function of markets.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 504', 'SEMINAR IN HUMAN RIGHTS AND INTERNATIONAL LAW', '10084', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'BH 237', 'Andrea Siqueira', 8, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advanced seminar that focuses on human rights discourse and the role international law, treaties and conventions play in addressing these rights globally. Course is interdisciplinary in theory and method.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 506', 'SEMINAR IN IDENTITY AND CONFLICT', '29710', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'GA 1134', 'Clemence Pinaud', 8, NULL, 'Seminar', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Advanced seminar examining concepts of nationalism and state ideology that shape the world''s collective identities and contribute to conflicts nationally and internationally.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 510', 'SEMINAR IN DIPLOMACY, SECURITY, GOVERNANCE', '32545', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'LI 026', 'Alina Williams', 4, NULL, 'Seminar', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'Advanced seminar examining the role of international organizations in maintaining global security and promoting global governance. Addresses issues of political and cultural diplomacy and their effect in international disputes.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 515', 'RESEARCH METHODS IN INTERNATIONAL STUDIES', '13657', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 009', 'Sarah Bauerle Danzman', 1, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced seminar on research methodology used in international studies. Completion before the student''s international experience/internship is strongly recommended.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 521', 'GLOBAL GOVERNANCE AND INTERNATIONAL ORGANIZATIONS', '10082', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 0003', 'Sarah Bauerle Danzman', 2, NULL, 'Seminar', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Examines the history, role, and operations of international organizations; explores theoretical approaches to studying global governance; and surveys debates on the scope, legitimacy, and accountability of global governance mechanisms.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 523', 'INTERNATIONAL SECURITY REGIMES', '11190', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 106', 'Michael De Groot', 1, NULL, 'Seminar', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Provides students with an overview of the theoretical and policy debates that comprise the field of international security. Over the course of the semester, participants will be exposed to a wide range of topics that collectively give a sense of the historical contexts and future trajectories of international security.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 525', 'INTERNATIONAL CLIMATE GOVERNANCE', '10479', 'Closed', 'Th Thursday 12:45 PM–3:15 PM', 'PV 270', 'Jessica O''Reilly', 0, NULL, 'Seminar', '3', 'SPEA', ARRAY[]::TEXT[], 'Study of climate issues with a focus on the effect of global governance institutions and NGOs on climate policy and action. May include attendance at national and/or international climate conferences as part of official IU delegation.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 680', 'INTERNATIONAL STUDIES MASTER''S CAPSTONE', '8288', 'Class Status', NULL, NULL, 'Jessica O''Reilly', 5, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'This seminar is designed to consolidate the studies of master''s students who have completed all International Studies graduate degree requirements. Students must complete a project that addresses an issue appropriate to international studies.', ARRAY[]::TEXT[], NULL),
    ('INTL-I 702', 'INDEPENDENT STUDY IN GLOBAL STUDIES', '6068', 'Class Status', NULL, NULL, 'Jessica O''Reilly', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Independent research, investigation, and synthesis of scholarship that crosses disciplines. Supervised by a faculty member upon the approval of the department.', ARRAY[]::TEXT[], NULL),
    ('INTL-L 250', 'INTRODUCTION TO INTERNATIONAL LAW AND LEGAL INSTITUTIONS', '29892', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GA 1112', 'Feisal Istrabadi', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the central instruments and methodological tools of international law through study of international law cases, major treaties, and key institutions such as the United Nations and the International Criminal Court.', ARRAY[]::TEXT[], NULL),
    ('INTL-L 250', 'INTRODUCTION TO INTERNATIONAL LAW AND LEGAL INSTITUTIONS', '35038', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'TV 226', 'Ahmed Elbasyouny', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduces the central instruments and methodological tools of international law through study of international law cases, major treaties, and key institutions such as the United Nations and the International Criminal Court.', ARRAY[]::TEXT[], NULL),
    ('INTL-L 356', 'INTERVENTION AND SOVEREIGNTY', '32308', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 343', 'Emma Gilligan', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Discussion of the origins and evolution of international laws on genocide, atrocity, and crimes against humanity, and exploration of the philosophical and legal bases for international laws on conflict.', ARRAY[]::TEXT[], NULL),
    ('INTL-X 390', 'INDIVIDUAL READINGS IN INTERNATIONAL STUDIES', '7069', 'Class Status', NULL, NULL, 'Clemence Pinaud', 10, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Students conduct individual research projects on an international issue under the direction of a faculty member. Student and faculty member should develop a project and submit a "contract" to the department for approval.', ARRAY[]::TEXT[], NULL),
    ('JSTU-C 221', 'ISRAEL ON SOCIAL MEDIA: CONCEPTIONS, MISCONCEPTIONS, AND CONTROVERSIES', '13978', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 118', 'Guenther Jikeli', 8, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course explores the complex and evolving landscape of perceptions surrounding Israel in the realm of social media. We will explore how different social media platforms are used to promote different narratives about Israel, and how these narratives can influence public opinion.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('JSTU-C 334', 'WHAT IS MIDDLE EASTERN? PERSPECTIVES GAINED THROUGH COMPARISON WITH ISRAEL', '30513', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 313', 'Aziza Khazzoom', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines work that makes claims about Middle Eastern dynamics, by describing histories, gender regimes, secular/religious tensions, etc, that are perceived as common across Middle Eastern societies. Uses Israel, a possible Middle Eastern society, to provide a fresh perspective on what does and does not hold the Middle East together.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture
COLL INTENSIVE WRITING SECTIONS'], NULL),
