    ('JSTU-H 520', 'COLLOQUIUM IN JEWISH STUDIES', '5393', 'Class Status', 'W Wednesday 3:10 PM–5:10 PM', 'SY 037', 'Sarah Imhoff', 11, NULL, 'Colloquium', '4', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course is an interdisciplinary survey of various methodologies and approaches to the field of Jewish Studies.', ARRAY[]::TEXT[], NULL),
    ('JSTU-H 595', 'DIRECTED READINGS IN JEWISH STUDIES', '2048', 'Class Status', NULL, NULL, 'Laura Carlson Hasler', 7, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], 'Directed readings in various topics in Jewish Studies; topic, credit hours and readings to be determined in consultation with faculty member with whom the student wishes to work.', ARRAY[]::TEXT[], NULL),
