COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('JSTU-J 303', 'ARTS AND HUMANITIES TOPICS IN JEWISH STUDIES', '11600', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 216', 'Laura Carlson Hasler', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected arts and humanities topics and issues in Jewish Studies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 303', 'ARTS AND HUMANITIES TOPICS IN JEWISH STUDIES', '34532', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:25 PM', 'LH 135', 'Herbert Marks', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected arts and humanities topics and issues in Jewish Studies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 304', 'SOCIAL AND HISTORICAL TOPICS IN JEWISH STUDIES', '14391', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'WH 002', 'Dina Spechler', 2, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Selected social and historical topics and issues in Jewish Studies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 304', 'SOCIAL AND HISTORICAL TOPICS IN JEWISH STUDIES', '30517', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'SY 137', 'Aziza Khazzoom', 14, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Selected social and historical topics and issues in Jewish Studies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 304', 'SOCIAL AND HISTORICAL TOPICS IN JEWISH STUDIES', '31479', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'BH 307', 'Daniel Miehling', 6, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Selected social and historical topics and issues in Jewish Studies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 359', 'EXPLORING JEWISH IDENTITY TODAY', '14102', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 144', 'Jeremiah Lockwood', 4, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'When people describe what they believe, do, create, or experience as "Jewish," what do they mean? Using multiple perspectives and multiple forms of media, we will explore how different communities--from orthodox Jews to evangelical Christians--incorporate senses of Judaism into their cultural, religious, racial, ethnic, and artistic identities.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('JSTU-J 403', 'ARTS AND HUMANITIES TOPICS IN JEWISH STUDIES', '30547', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 315', 'Michael Weinman', 12, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Selected arts and humanities topics and issues in Jewish Studies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('JSTU-J 699', 'M.A. THESIS IN JEWISH STUDIES', '5909', 'Class Status', NULL, NULL, 'Laura Carlson Hasler', 9, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'M.A. thesis in Jewish Studies. The thesis should not exceed 40 pages or 12,000 words. Thesis defense before a committee of three faculty members, at least two of whom must be Jewish Studies faculty.', ARRAY[]::TEXT[], NULL),
    ('JSTU-L 270', 'COMING TO AMERICA: HISTORY AND MEMORY OF IMMIGRATION IN JEWISH LITERATURE', '14715', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 215', 'Stephen Katz', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies the encounter of Jews immigrating to America in the later nineteenth and early twentieth centuries. Readings (in English translation) of memoirs, prose fiction and poetry composed in English, Hebrew and Yiddish illustrate the clash of civilizations and ensuing acculturation. Assimilation and reciprocal effects are also explored.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('JSTU-L 380', 'MODERN HEBREW LITERATURE IN ENGLISH', '34624', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 125', 'Stephen Katz', 2, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Nineteenth-and twentieth-century fiction, poetry, essays, under such headings as assimilation (ideal or aberration?); ghetto and world; secularism versus tradition; ethnicity, land, and universalism; nation, religion, state; utopias and revolutions; nostalgia, self-hate, rejuvenation; portrayal of anti-Semitism in literature.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('JSTU-P 598', 'INTERNSHIP IN JEWISH STUDIES', '5482', 'Class Status', NULL, NULL, 'Laura Carlson Hasler', 10, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Through internships, students make particular use of their skills, learn new skills, and start to build professional contacts in their field of interest. S/F grading.', ARRAY[]::TEXT[], NULL),
    ('JSTU-X 170', 'LEADERSHIP IN JEWISH STUDIES', '11537', 'Class Status', 'Tu Tuesday 3:10 PM–5:10 PM', NULL, 'Dmitry Romashov', 12, NULL, 'Lecture', '1', NULL, ARRAY[]::TEXT[], 'Variable topic course, designed to be practical in nature. Allows students to study and apply leadership skills through obtaining leadership roles in the community.', ARRAY[]::TEXT[], NULL),
    ('JSTU-X 473', 'INTERNSHIP IN JEWISH STUDIES', '5193', 'Class Status', NULL, NULL, 'Dmitry Romashov', 23, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Through internships, students make particular use of their skills, learn new skills, and start to build professional contacts in the field of their interest. Students who wish to receive credit through Jewish Studies for their internship need to have a Jewish Studies faculty sponsor and are responsible for finding and securing their own internships.', ARRAY[]::TEXT[], NULL),
    ('JSTU-X 490', 'INDIVIDUAL READINGS IN JEWISH STUDIES', '2046', 'Class Status', NULL, NULL, 'Dmitry Romashov', 10, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Designed for advanced Jewish Studies students who wish to concentrate on a particular area of Judaic previously introduced to them in other courses.', ARRAY[]::TEXT[], NULL),
    ('LAMP-L 316', 'LAMP JUNIOR SEMINAR: ANALYTICAL PROBLEM SOLVING', '2050', 'Class Status', 'MWF Monday, Wednesday, Friday 1:15 PM–2:30 PM', 'KH 016', 'Kody Steffy', 12, NULL, 'Seminar', '3', 'KIRKWOOD HALL', ARRAY[]::TEXT[], 'A discussion course emphasizing the use of quantitative methods and analytical skills in exploring and solving business-related problems. Topics vary with the instructor and year and include mathematical modeling and operations research, organizational control, and corporate finance.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LAMP-X 373', 'INTERNSHIP FOR LAMP', '2051', 'Class Status', NULL, NULL, 'Stephen Benard', 19, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Provides an opportunity for students to receive credit for supervised, career-related, full-time work appropriate to LAMP.', ARRAY[]::TEXT[], NULL),
    ('LAMP-X 491', 'INDEPENDENT STUDY FOR HONORS', '8891', 'Class Status', NULL, NULL, 'Stephen Benard', 8, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Research and preparation of senior honors paper.', ARRAY[]::TEXT[], NULL),
    ('LATS-L 101', 'INTRODUCTION TO LATINO STUDIES', '30414', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 206', 'Judith Rodriguez', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'General inquiry into the historical and cultural heritage of Latinos who have lived or currently live in what is today the United States. Through readings and discussions, the course studies the varied histories or Mexican, Puerto Rican, Cuban and other Latin American peoples in the U.S.', ARRAY['IUB GenEd S&H credit
COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('LATS-L 111', 'LATINO FILM: AN INTRODUCTION AND OVERVIEW', '37322', 'Class Status', 'MW Monday, Wednesday 10:25 AM–12:55 PM', 'LI 048', 'John Nieto-Phillips', 13, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course examines U.S. films by and/or about Hispanics and Latinos/as (i.e. Mexican-American/Chicano, Puerto Rican/Boricus, and Cuban-American.) Throughout the semester we will explore the complex relationship between the constructions of Latino/a identities, Latino/a stereo-types, and the circumstances which Latinos encounter in the U.S. as portrayed in film.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('LATS-L 111', 'LATINO FILM: AN INTRODUCTION AND OVERVIEW', '34839', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 139', 'Charles Exdell', 0, NULL, 'Lecture', '3', 'WELLS LIBRARY', ARRAY[]::TEXT[], 'This course examines U.S. films by and/or about Hispanics and Latinos/as (i.e. Mexican-American/Chicano, Puerto Rican/Boricus, and Cuban-American.) Throughout the semester we will explore the complex relationship between the constructions of Latino/a identities, Latino/a stereo-types, and the circumstances which Latinos encounter in the U.S. as portrayed in film.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('LATS-L 200', 'AMERICAN BORDERLANDS', '6238', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WH 004', 'Juan Mora', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'This course will examine lived experience in North American Borderlands. It will touch on themes of migration, empire, race, gender, indigenous and imperial actors and their cultural production, and ethnic, racial and national identities in present-day borderlands between the US, Canada, Mexico, the Pacific, and the Caribbean.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('LATS-L 320', 'ADVANCED TOPICS IN LATINO LITERATURE AND CULTURE', '30412', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'TV 226', 'Alberto Varon', 0, NULL, 'Seminar', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on Latina/o literary and cultural production to provide an in-depth examination of a particular subject, area or theme in Latina/o Studies. Possible topics include a survey of a specific historical period in Latina/o literature, a literary form or genre in Latina/o literature, or the methodologies employed by Latina/o cultural studies.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Diversity in U.S.'], NULL),
    ('LATS-L 398', 'ARTS AND HUMANITIES TOPICS IN LATINO STUDIES', '37062', 'Class Status', 'TuTh Tuesday, Thursday 9:10 AM–11:40 AM', 'FF 114', 'Olga Rodriguez-Ulloa', 16, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'Examination of literature, art, music, performance, and other forms of aesthetic expression pertaining to the study and understanding of Latinos. Topics may vary.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('LATS-L 599', 'INDIVIDUALIZED READINGS IN LATINO STUDIES', '4703', 'Class Status', NULL, NULL, 'Sylvia Martinez', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Students must complete an agreement including goals of the course, number of readings, titles of readings (if possible) and the date of work it is to be completed.', ARRAY[]::TEXT[], NULL),
    ('LATS-L 599', 'INDIVIDUALIZED READINGS IN LATINO STUDIES', '9957', 'Class Status', NULL, NULL, 'Sylvia Martinez', 1, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], 'Students must complete an agreement including goals of the course, number of readings, titles of readings (if possible) and the date of work it is to be completed.', ARRAY[]::TEXT[], NULL),
