    ('LAW-B 502', 'FUNDAMENTALS OF CONTRACT LAW', '35970', 'Class Status', 'MW Monday, Wednesday 1:50 PM–3:15 PM', 'LW 214', 'Lisa Farnsworth', 13, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course is for students at the law school who are not pursuing a JD degree. It focuses on the principal aspects of contract law including the substantive and remedial aspects of agreements; formation; rights and responsibilities of parties; and legal and equitable remedies in cases of breach or nonperformance.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 504', 'INTRODUCTION TO LAW', '34597', 'Class Status', 'TuTh Tuesday, Thursday 4:30 PM–5:55 PM', 'LW 214', 'Gabrielle Goodwin', 10, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course offers an overview of the American legal system and is designed for law students in the non-J.D. graduate programs.', ARRAY[]::TEXT[], NULL),
