    ('LAW-B 514', 'PRIVATE PRACTICE EXTERNSHIP', '8026', 'Class Status', NULL, NULL, 'Lauren Violi', 36, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'Program encourages students to explore careers in private practice by doing internships and experience in private practice settings including law firms and corporate law departments. Internships include legal work assigned by the attorney-supervisor and an academic component assigned by faculty member to encourage reflection on issues of ethics and practice.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 514', 'PRIVATE PRACTICE EXTERNSHIP', '8027', 'Class Status', NULL, NULL, 'Staff', 50, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'Program encourages students to explore careers in private practice by doing internships and experience in private practice settings including law firms and corporate law departments. Internships include legal work assigned by the attorney-supervisor and an academic component assigned by faculty member to encourage reflection on issues of ethics and practice.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 528', 'ADVANCED APPELLATE ADVOCACY', '14586', 'Class Status', 'Tu Tuesday 8:45 AM–10:45 AM', 'LW 206E', 'Lane McFadden', 2, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This will be the course for students to receive credit that are participating on the Moot Court Executive Board.', ARRAY[]::TEXT[], NULL),
