    ('LAW-B 530', 'LEGAL WRITING & RESEARCH METHODS FOR MCL AND LLM STUDENTS', '5559', 'Class Status', 'MW Monday, Wednesday 12:00 PM–12:55 PM', 'LW 214', 'Lisa Farnsworth', 13, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This introduction to legal writing and research is required in the fall semester of LLM and MCL candidates and is designed to meet the specific pedagogical needs of non-native speakers who received their legal education abroad.', ARRAY[]::TEXT[], NULL),
