    ('LAW-B 533', 'CIVIL PROCEDURE', '10887', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 10:35 AM–11:50 AM', 'LW 125', 'Andrew Hammond', 28, NULL, 'Lecture', '4', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Devices within the legal system for the resolution of civil disputes, including jurisdiction of courts over persons, property, and subject matter; functions of pleadings, pre-trial motions, and discovery; appeals; revision and vacation of judgments; collateral attack on judgments; res judicata; organization of the court system.', ARRAY[]::TEXT[], NULL),
