    ('LAW-B 534', 'PROCEDURE 2', '6253', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 2:20 PM–3:15 PM', 'LW 121', 'Andrew Hammond', 59, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Devices within the legal system for the resolution of civil disputes, including jurisdiction of courts over persons, property, and subject matter; functions of pleadings, pre-trial motions, and discovery; appeals; revision and vacation of judgments; collateral attack on judgments; res judicata; organization of the court system.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 538', 'SEMESTER PUBLIC INTEREST PROGRAM', '15031', 'Class Status', NULL, NULL, 'David Williams', 4, NULL, 'Internship', '8', NULL, ARRAY[]::TEXT[], 'Select upper-level students spend an entire semester in Washington, D.C., NY, LA or Chicago as public interest interns with nonprofit corporations or federal, state, or local government agencies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 538', 'SEMESTER PUBLIC INTEREST PROGRAM', '5284', 'Class Status', NULL, NULL, 'Sarah Hughes', 12, NULL, 'Internship', '8', NULL, ARRAY[]::TEXT[], 'Select upper-level students spend an entire semester in Washington, D.C., NY, LA or Chicago as public interest interns with nonprofit corporations or federal, state, or local government agencies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 539', 'LAWYERING IN THE PUBLIC INTEREST', '5905', 'Class Status', NULL, 'WB WEB', 'Sarah Hughes', 4, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This is a skills-based class on lawyering public interest to be held in Washington, D.C., for third year students also enrolled in the Washington Externship Program. The course will focus on the kinds of activities in which lawyer practicing in the area are often engaged, such as comments on proposed agency rules, analyses of pending legislation for clients, or development of legislative strategies and drafting talking points. Sessions will be arranged to have alumni meet with the students to discuss insights/practice tips they have gained from experience.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 542', 'LEGAL RESEARCH AND WRITING', '2053', 'Class Status', 'ThF Thursday, Friday 9:50 AM–10:45 AM', 'LW 120', 'Robert Downey', 8, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
