    ('LAW-B 542', 'LEGAL RESEARCH AND WRITING', '33717', 'Class Status', 'ThF Thursday, Friday 9:50 AM–10:45 AM', 'LW 125', 'Lane McFadden', 7, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 545', 'CRIMINAL LAW EXTERNSHIP', '9264', 'Class Status', NULL, NULL, 'Katie Beck', 45, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'Student will work at prosecutors'' and public defenders'' offices. Student is expected to complete approximately 50-60 hours of work for each credit; maintain a time/activity log; submit 2-3 reflective essays about the clinical experience; participate in a mid-term and final academic conference; submit one work-product sample and complete a final self-evaluation form.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 545', 'CRIMINAL LAW EXTERNSHIP', '13117', 'Class Status', NULL, NULL, 'Staff', 50, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'Student will work at prosecutors'' and public defenders'' offices. Student is expected to complete approximately 50-60 hours of work for each credit; maintain a time/activity log; submit 2-3 reflective essays about the clinical experience; participate in a mid-term and final academic conference; submit one work-product sample and complete a final self-evaluation form.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 547', 'PUBLIC INTEREST INTERNSHIP PROGRAM', '6645', 'Class Status', NULL, NULL, 'Katie Beck', 32, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'The Public Interest Internship Program students to explore careers in the public interest by permitting students to obtain credit for work done in public service and public interest settings. Students are supervised by a faculty member and an attorney at the internship site. A critical component of the internship is the academic component assigned by the faculty member that is designed to encourage students to think reflectively and critically about the practice of law and the ethical issues it poses.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 547', 'PUBLIC INTEREST INTERNSHIP PROGRAM', '13116', 'Class Status', NULL, NULL, 'Staff', 50, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'The Public Interest Internship Program students to explore careers in the public interest by permitting students to obtain credit for work done in public service and public interest settings. Students are supervised by a faculty member and an attorney at the internship site. A critical component of the internship is the academic component assigned by the faculty member that is designed to encourage students to think reflectively and critically about the practice of law and the ethical issues it poses.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 548', 'FINANCIAL INSTITUTIONS', '9100', 'Closed', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 214', 'Sarah Hughes, Alexis Lanham', 0, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course explores financial regulation in the aftermath of the most systemic financial crisis in the last 70 years, which was followed by a major shift in regulatory design.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 551', 'INTELLECTUAL PROPERTY EXTERNSHIP', '5449', 'Class Status', NULL, NULL, 'Lauren Violi', 50, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'The Intellectual Property Externship program consists of a series of externship opportunities developed and administered by the law school in connection with the Center for Intellectual Property Research. The number and type of externships will vary from semester to semester. Some may be available during the summer. Intellectual Property externship opportunities will be posted at designated times during the fall and spring semesters. Students will ordinarily apply directly to the externship hosts, who will be responsible for selecting externs. Student externs will then enroll in the Intellectual Property Externship course.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 554', 'LEGISLATION', '8519', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 8:45 AM–9:40 AM', 'LW 214', 'William Popkin', 2, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 558', 'CONSERVATION LAW CLINIC', '3474', 'Closed', 'Th Thursday 2:20 PM–4:20 PM', 'LW 125', 'Christian Freitag', 0, NULL, 'Clinic', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Opportunity for second and third year law students to represent clients who need assistance with natural resource conservation problems. Skills essential to conservation law practice will be discussed, and progress with clients, cases, and matters are reviewed. While unscheduled interaction with the Clinic Director and other students working on clinic matters is expected, each student will prepare for schedule meetings with the Clinic Director at least bi-weekly.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 561', 'ENTREPRENEURSHIP LAW CLINIC', '3366', 'Closed', 'Tu Tuesday 4:30 PM–6:30 PM', 'HD TBA', 'Mark Need', 0, NULL, 'Clinic', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Primarily for fourth-year JD/MBA candidates. The Clinic will focus largely on legal tasks related to early-stage businesses, including (1) obtaining permits and licenses; (2) researching and registering intellectual property rights; (3) negotiating contracts and leases; (4) advising on appropriate business form; and (5) drafting necessary formation documents. ELC students will also draw on the resources and expertise of the Kelley School of Business''s Johnson Center for Entrepreneurship while participating in the evaluation, development, and financing of such companies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 564', 'LITIGATION', '14453', 'Class Status', 'W Wednesday 3:25 PM–5:25 PM', 'LS 219', 'Amy Applegate', 4, NULL, 'Lecture', '2', '4TH & INDIANA-LEWIS BLDG', ARRAY[]::TEXT[], 'The course is primarily designed to give you experience drafting pretrial documents a lawyer would be expected to write in the pretrial litigation context.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 569', 'NONPROFIT ORGANIZATIONS', '33718', 'Class Status', 'F Friday 8:45 AM–11:45 AM', 'LW 214', 'Philip Purcell', 11, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Legal issues related to nonprofit organizations, with an emphasis upon charitable organizations and the federal and state law governing such entities. Topics will include qualification for tax-exempt status and the special duties and rights of nonprofits.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 570', 'FUNDAMENTALS OF U.S. CONSTITUTIONAL LAW', '35951', 'Class Status', 'Tu Tuesday 10:55 AM–12:55 PM', 'LW 203', 'Donald Gjerdingen', 7, NULL, 'Lecture', '2–3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Constitutional law dominates American life from foreign policy and regulation of business to the daily duties of police officers on the beat. This course will survey contemporary and historical standards under the U.S. Constitution for federalism, separation of powers, and individual rights for lawyers trained outside the United States. Special emphasis will be placed on the pre-Civil War, Civil War to 1937, and modern periods of Constitutional law and American legal thought, as well as on contemporaneous events in American history.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 572', 'INTELLECTUAL PROPERTY LAW CLINIC', '6652', 'Class Status', 'Th Thursday 8:30 AM–12:00 PM', 'HD TBA', 'Norman Hedges', 22, NULL, 'Clinic', '1–4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The IP Clinic provides students the opportunity to work directly with clients on actual intellectual property law matters (e.g. patent, trademark, and copyright applications, interaction with the United States Patent & Trademark Office (USPTO), licenses, due diligence, and non-infringement and/or invalidity opinions).', ARRAY[]::TEXT[], NULL),
    ('LAW-B 575', 'CONSTITUTIONAL DESIGN IN MULTIETHNIC COUNTRIES', '6646', 'Class Status', 'ThF Thursday, Friday 10:25 AM–11:50 AM', 'HD TBA', 'David Williams', 8, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Examination of constitutional design as a mean of facilitating democracy (polyarchy) in multiethnic countries without exacerbating ethnic tensions. Specific focus on such issues as relationships between branches of several powers and between central and local authorities, and electoral systems in contemporary national contexts, from Lebanon and Fiji to Switzerland and South Africa.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 582', 'MERGERS AND ACQUISITIONS', '12562', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 3:25 PM–4:20 PM', 'LW 216', 'Cynthia Williams', 17, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'All legal aspects of mergers and acquisitions. Examines differences between negotiated and hostile transactions, stock deals and asset deals, the effect of due diligence, and fiduciary obligations of directors on both sides of a transaction, as well as the impact of the new Sarbanes - Oxley Act of 2002, self-regulatory organization rules, and other changes in corporate governance on transactions. Also reviews the role the target''s state of incorporation has on the process.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 590', 'ENTERTAINMENT LAW', '14455', 'Class Status', 'TuW Tuesday, Wednesday 1:15 PM–2:10 PM', 'LW 122', 'Robert Meitus', 5, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Course will provide student with the opportunity to develop both a practical understanding of representing creative and business interests in the field of music, publishing and film and television and a theoretical understanding of the broader intellectual property and constitutional issues at stake with regard to control of creative content.', ARRAY['Class uses IU eTexts'], NULL),
    ('LAW-B 591', 'CHILD REPRESENTATION PRACTICUM', '12563', 'Class Status', 'F Friday 8:45 AM–11:45 AM', 'LW 216', 'Rachel Vilensky, Joel Wieneke', 4, NULL, 'Practicum', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Students will research issues regarding the Child in Need of Services or Termination of Parental Rights case, investigate placement options at the client''s direction, and advocate for the youth''s wishes. Alongside the supervising attorney, the student will prepare for hearings and advocate in court for the wishes of the youth.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 592', 'LAW AND POLITICAL THEORY', '34865', 'Closed', 'Tu Tuesday 3:00 PM–5:00 PM', 'HD TBA', 'Scott Shackelford, Jessica Steinberg', 0, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The course will address the relationship of the traditional approach to the law to many postulates about the law implicit in political theory.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 600', 'DIRECTED READING', '2057', 'Class Status', NULL, NULL, 'Staff', 89, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 601', 'CRIMINAL PROCEDURE: INVESTIGATION', '9668', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 121', 'Ryan Scott', 49, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Criminal investigative techniques and their control; due process in the criminal law context, police at an institution. Problems of entrapment, interrogation, bail, identification; right of accused to counsel.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 602', 'CRIMINAL PROCEDURE: TRIAL', '14456', 'Class Status', 'Th Thursday 1:15 PM–4:15 PM', 'LW 124', 'Cindy Cho', 48, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Pleading, adjudication and corrections in criminal cases; charging decision; grand jury; preliminary hearings and arraignment. Pre-trial discovery; trial. Post-conviction remedies; double jeopardy; probation and parole.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 613', 'CONSUMER LAW', '33728', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 203', 'Gary Pieples', 1, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course examines contemporary consumer law. The class is organized around a consumer transaction, including how businesses attract consumers, the terms of the products or services purchased, and the remedies or enforcement tools available if the deal goes awry.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 614', 'THE LEGAL PROFESSION', '10646', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'LW 123', 'Anne McFadden', 10, NULL, 'Lecture', '1', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course explores the rules of professional responsibility, the different contexts in which attorneys practice, and the set of professional competencies shared by highly successful attorneys, regardless of their practice setting.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 616', 'MODERN LAW PRACTICE I', '34265', 'Closed', 'Non Standard Session', NULL, 'John Rompon, William Henderson', 0, NULL, 'Internship', '1', NULL, ARRAY[]::TEXT[], 'This course introduces students to the tools and methodologies used to drive efficiency, predictability, and quality within the legal industry''s most advanced legal departments and service providers.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 617', 'MODERN LAW PRACTICE II', '15251', 'Class Status', NULL, NULL, 'William Henderson', 5, NULL, 'Lecture', '2', NULL, ARRAY[]::TEXT[], 'Transactions combines operational skills with substantive law, first by deconstructing a series of transactions that are common in the tech industry; and second, by engaging in a multiclass simulation designed to provide students with experience working on a complex corporate transaction from inception to closing.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 618', 'MODERN LAW PRACTICE FIELD PLACEMENT PROGRAM', '15252', 'Class Status', NULL, NULL, 'William Henderson', 5, NULL, 'Lecture', '8', NULL, ARRAY[]::TEXT[], 'The core of the program is a semester-long field placement that includes established and regular communication among participating students, the supervising attorney, and the course instructor.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 620', 'NEGOTIATIONS', '10647', 'Closed', 'M Monday 5:35 PM–7:35 PM', 'LW 216', 'James Hoeksema', 0, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Analysis of general techniques, models and ethical and cultural negotiating considerations. Exploring the role of the lawyer in negotiations. Emphasis on developing actual negotiating, experience in problem situations. Drafting considerations. Strong problem orientation toward business settings, some consideration of lawsuit settlement and other areas.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 634', 'ADVANCED CONSTITUTIONAL LAW', '10648', 'Class Status', 'M Monday 9:00 AM–11:30 AM', 'FF 017', 'Anthony Fargo', 3, NULL, 'Lecture', '3', 'FRANKLIN HALL', ARRAY[]::TEXT[], 'A study of major cases from the most recent term of the United States Supreme Court, a representative selection of cases not decided by the Supreme Court, and important recent commentary on the Court''s work.', ARRAY['Class uses IU eTexts'], NULL),
    ('LAW-B 639', 'ADVANCED LEGAL RESEARCH', '5906', 'Class Status', 'MTu Monday, Tuesday 10:55 AM–11:50 AM', 'LW 214', 'Ashley Ahlbrand, Morgan Kelly', 7, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course will offer students an opportunity to gain in-depth working knowledge of legal research methods and resources. The course will emphasize use and comparison of a broad range of legal research tools, including traditional print sources and a host of electronic materials.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 639', 'ADVANCED LEGAL RESEARCH', '9666', 'Closed', NULL, 'WB WEB', 'Jennifer Morgan', 0, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course will offer students an opportunity to gain in-depth working knowledge of legal research methods and resources. The course will emphasize use and comparison of a broad range of legal research tools, including traditional print sources and a host of electronic materials.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 639', 'ADVANCED LEGAL RESEARCH', '11439', 'Closed', NULL, 'WB WEB', 'Margaret Kiel-Morse', 0, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course will offer students an opportunity to gain in-depth working knowledge of legal research methods and resources. The course will emphasize use and comparison of a broad range of legal research tools, including traditional print sources and a host of electronic materials.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 642', 'APPELLATE ADVOCACY', '12564', 'Class Status', 'Th Thursday 8:45 AM–9:40 AM', 'LW 125', 'Lane McFadden', 41, NULL, 'Lecture', '1', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Fundamental skills of appellate advocacy, emphasis being equally divided between brief-writing and oral argument. The first phase of the course consists of classroom instruction, primarily in the form of lectures by appellate practitioners and judges together with video-taped demonstrations of oral argument. Second phase consists of assignment to students of a case to brief and argue before moot court.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 642', 'APPELLATE ADVOCACY', '14511', 'Class Status', 'W Wednesday 4:30 PM–5:25 PM', 'LW 122', 'Lane McFadden', 57, NULL, 'Lecture', '1', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Fundamental skills of appellate advocacy, emphasis being equally divided between brief-writing and oral argument. The first phase of the course consists of classroom instruction, primarily in the form of lectures by appellate practitioners and judges together with video-taped demonstrations of oral argument. Second phase consists of assignment to students of a case to brief and argue before moot court.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 645', 'TRUSTS & ESTATES', '9060', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 10:55 AM–11:50 AM', 'LW 121', 'Jeffrey Stake', 62, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Trusts & Estates will cover functions and purposes of wills and trusts; intestate succession; limitations on testation; execution, revocation, and revalidation of wills; creation, modification, and termination of trusts; construction of wills and trusts; and the law relating to future interests, including the Rule against Perpetuities.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 650', 'INTRODUCTION TO INCOME TAXATION', '2058', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 1:15 PM–2:10 PM', 'LW 120', 'Stephanie McMahon', 23, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 653', 'CORPORATIONS', '5273', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 3:25 PM–4:20 PM', 'LW 121', 'Karen Woody', 59, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Continuation of B633. Selection of business form, location and method of financing; mechanics of incorporation; distribution of powers and obligations among directors, officers, and shareholders; charter amendments, mergers, consolidations, dissolutions.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 654', 'PRODUCTS LIABILITY', '33719', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 2:20 PM–3:15 PM', 'LW 213', 'Jody Madeira', 18, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'In-depth study of the law relating to manufacturers'' and distributors'' liability for defective consumer products, including the main theories of liability and their legislative and judicial bases, and the interaction of contract and tort law and economics, sociology and jurisprudence.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 658', 'THE LAW AND EDUCATION', '5977', 'Closed', 'Non Standard Session', 'WB WEB', 'Janet Decker, Hannah Gahimer', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A study of the role of law and legal institutions in shaping elementary and secondary education and in determination of educational issues. Case analysis will be integrated with readings on issues of educational theory and practice, proposals for changes, and the history of education in the United States.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 658', 'THE LAW AND EDUCATION', '9116', 'Closed', 'Non Standard Session', 'WB WEB', 'Jennifer Rippner, Janet Decker', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A study of the role of law and legal institutions in shaping elementary and secondary education and in determination of educational issues. Case analysis will be integrated with readings on issues of educational theory and practice, proposals for changes, and the history of education in the United States.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 662', 'COPYRIGHT LAW', '33720', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 213', 'Susan deMaine', 20, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Legal protection of various forms of literary, artistic and intellectual property. Primary attention is directed to rights and remedies under the Federal Copyright Act, with some consideration given to adjacent areas of the law of trademarks and business torts.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 663', 'LABOR LAW 1', '14458', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 10:55 AM–11:50 AM', 'LW 120', 'Kenneth Dau-Schmidt', 9, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 668', 'CONSTITUTIONAL LAW II', '10649', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 120', 'Rafael Macía Briedis', 23, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'To extend the basic Constitutional law coverage of the first year course. Principal area will be the First Amendment (freedom of speech, press and assembly).', ARRAY[]::TEXT[], NULL),
    ('LAW-B 669', 'IMMIGRATION LAW', '13060', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 1:15 PM–2:10 PM', 'LW 124', 'Jayanth Krishnan', 27, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'A study of the statutes, regulations, administrative decisions, and reported cases which define the rights of aliens seeking to enter the United States, to remain in the country, or to secure and retain U.S. citizenship and an examination of the legality of federal and state rules imposing special limits on alien rights.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 672', 'SECURED TRANSACTIONS', '14459', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 3:25 PM–4:20 PM', 'LW 124', 'Christopher Ryan', 30, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 674', 'LAW JOURNAL', '2059', 'Class Status', NULL, NULL, 'Jayanth Krishnan', 54, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 674', 'LAW JOURNAL', '2060', 'Class Status', NULL, NULL, 'Steve Sanders', 29, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 674', 'LAW JOURNAL', '5317', 'Class Status', NULL, NULL, 'Luis Fuentes-Rohwer', 56, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 674', 'LAW JOURNAL', '5318', 'Class Status', NULL, NULL, 'Michael Mattioli', 74, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 674', 'LAW JOURNAL', '6889', 'Class Status', NULL, NULL, 'David Williams', 86, NULL, 'Readings', '1', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 679', 'STUDENT LEGAL SERVICES CLINIC', '10651', 'Class Status', 'Th Thursday 3:35 PM–5:35 PM', 'LW 222', 'Stacee Williams', 1, NULL, 'Internship', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'A one year course in which the first semester is devoted to the study of interviewing and counseling techniques, legal ethics and law office management; the second semester the model studied earlier is applied to clients through Student Legal Services.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 680', 'EMPLOYMENT DISCRIMINATION', '8520', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 9:50 AM–10:45 AM', 'LW 216', 'Deborah Widiss', 13, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 684', 'STRATEGIES OF LEGAL WRITING', '13028', 'Class Status', 'MW Monday, Wednesday 8:45 AM–9:40 AM', 'LW 203', 'Brennan Murphy', 5, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course is designed to enhance student success in law school and on the bar exam by further strengthening critical legal analysis skills, with a particular emphasis on information processing and written legal analysis for exams.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 684', 'STRATEGIES OF LEGAL WRITING', '14619', 'Class Status', 'MW Monday, Wednesday 1:15 PM–2:10 PM', 'LW 203', 'Brennan Murphy', 1, NULL, 'Lecture', '2', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course is designed to enhance student success in law school and on the bar exam by further strengthening critical legal analysis skills, with a particular emphasis on information processing and written legal analysis for exams.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 686', 'CIVIL PROTECTION ORDER CLINIC', '34587', 'Class Status', 'Tu Tuesday 4:30 PM–6:30 PM', 'LW 222', 'Maryann Williams', 1, NULL, 'Clinic', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'The Civil Protection Order Clinic is a public interest-based clinic that provides students with hands-on legal experience representing clients who need legal assistance obtaining or renewing civil protection orders.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 688', 'COMMUNITY LEGAL CLINIC', '33729', 'Class Status', 'Th Thursday 8:45 AM–11:45 AM', 'LS 219', 'Gary Pieples', 5, NULL, 'Lecture', '3', '4TH & INDIANA-LEWIS BLDG', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 698', 'JUDICIAL FIELD PLACEMENTS', '2061', 'Class Status', NULL, NULL, 'Lauren Violi', 39, NULL, 'Internship', '1–4', NULL, ARRAY[]::TEXT[], 'Students'' work is directed by the judge and law clerks, and reviewed by the professor. In addition to performing approximately 100 hours of work in chambers, students will also meet periodically during the semester with the professor and complete a series of short reflective essays on their experience.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 704', 'THESIS RESEARCH', '9170', 'Class Status', NULL, NULL, 'Staff', 50, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'This credit will be available to LLM students who are working toward the completion of their degree program''s credit-hours requirement for thesis research.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 705', 'DISSERTATION RESEARCH', '9169', 'Class Status', NULL, NULL, 'Staff', 39, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], 'This course will be available to PhD or SJD students who are working toward the completion of their degree program''s credit-hours requirement for dissertation research.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 706', 'RESEARCH', '2062', 'Class Status', NULL, NULL, 'Staff', 89, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 706', 'RESEARCH', '5287', 'Class Status', NULL, NULL, 'Staff', 9, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 706', 'RESEARCH', '5354', 'Class Status', NULL, NULL, 'Staff', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 707', 'DIRECTED RESEARCH', '6647', 'Class Status', NULL, NULL, 'Staff', 98, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'A student may engage in collaborative research with a faculty member under the faculty member''s supervision. Such research may facilitate a faculty member''s work and may be on a topic identified by the faculty member, but must both involve independent research by the student and convey the fruits of that research through one or more papers, memos, or other written products prepared by the student.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 707', 'DIRECTED RESEARCH', '8675', 'Class Status', NULL, NULL, 'Staff', 19, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'A student may engage in collaborative research with a faculty member under the faculty member''s supervision. Such research may facilitate a faculty member''s work and may be on a topic identified by the faculty member, but must both involve independent research by the student and convey the fruits of that research through one or more papers, memos, or other written products prepared by the student.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 708', 'PRIVACY LAW', '7242', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 3:25 PM–4:20 PM', 'LW 213', 'Joseph Tomain', 10, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Some common law precedents on privacy will be discussed in light of shifting ideas of the "public interest." The focus will be on present threats to privacy, the ability of the judicial process using civil remedies to give meaningful relief, and policy considerations.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 708', 'PRIVACY LAW', '8180', 'Class Status', NULL, 'WB WEB', 'Joseph Tomain', 35, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Some common law precedents on privacy will be discussed in light of shifting ideas of the "public interest." The focus will be on present threats to privacy, the ability of the judicial process using civil remedies to give meaningful relief, and policy considerations.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 709', 'TRANSACTION DRAFTING', '5907', 'Closed', 'MW Monday, Wednesday 4:30 PM–5:55 PM', 'LW 213', 'Mark Need', 0, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Drafting documents to carry various agreements into effect, including large leasing agreements, mortgages, secured transactions, property settlement agreements, buy-sell agreements, and pre-incorporation agreements.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 710', 'INDEPENDENT CLINICAL PROJECTS', '2063', 'Class Status', NULL, NULL, 'Staff', 40, NULL, 'Internship', '1–4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Independent clinical project supervised by a faculty member in whose special field of competence the project lies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 710', 'INDEPENDENT CLINICAL PROJECTS', '2064', 'Class Status', NULL, NULL, 'Staff', 50, NULL, 'Internship', '1–4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Independent clinical project supervised by a faculty member in whose special field of competence the project lies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 710', 'INDEPENDENT CLINICAL PROJECTS', '9852', 'Class Status', 'M Monday 4:45 PM–6:00 PM', 'WB WEB', 'Siddharth Bose, Scott Shackelford, Isak Nti Asare', 11, NULL, 'Internship', '1–4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Independent clinical project supervised by a faculty member in whose special field of competence the project lies.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 712', 'TEACHING FELLOW', '12674', 'Class Status', NULL, NULL, 'Asaf Lubin', 46, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'The Teaching Fellow course awards academic credit to upper-level students who serve as Teaching Fellows in classes they have already completed.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 713', 'ADMINISTRATIVE LAW', '12566', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 2:20 PM–3:15 PM', 'LW 120', 'John Applegate', 25, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 714', 'DELIBERATIVE LEADERSHIP', '34287', 'Closed', 'W Wednesday 5:35 PM–8:40 PM', 'LW 214', 'William Henderson', 0, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Deliberative Leadership is unique seminar that focuses on leadership - the importance of leaders to the success of our public and private institutions; the attributes of leaders worth following; and focused class discussion and personal reflection on when, how, and why certain people ascend to positions of leadership.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 720', 'ADVANCED TRIAL PRACTICE', '9858', 'Class Status', 'W Wednesday 4:30 PM–7:30 PM', 'LW 215', 'Mary Ellen Diekhoff', 1, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Student preparation of an entire piece of litigation from initial client interview and investigation through pleadings, motions, discovery and a pre-trial conference, to the trial, verdict, judgment and post-trial motions.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 722', 'TRIAL ADVOCACY', '8521', 'Class Status', 'M Monday 4:30 PM–6:30 PM', 'LW 215 LW 215', 'Mary Ellen Diekhoff', 1, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 723', 'EVIDENCE', '3652', 'Class Status', 'MTu Monday, Tuesday 4:30 PM–5:55 PM', 'LW 121', 'Jennifer Oliva', 55, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 726', 'INTELLECTUAL PROPERTY ANTITRUST', '12567', 'Class Status', 'MTu Monday, Tuesday 3:25 PM–4:50 PM', 'LW 203', 'Donald Knebel', 13, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course will focus on the interplay between the antitrust laws and laws protecting intellectual property such as inventions, works of authorship and trademarks. Although both sets of laws are ultimately intended to make our economy more innovative and productive, their distinct ways of accomplishing that objective often seem to put them at odds with each other and courts are routinely called upon to resolve those conflicts.', ARRAY[]::TEXT[], NULL),
    ('LAW-B 727', 'SECURITIES REGULATION I', '11440', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 10:55 AM–11:50 AM', 'LW 213', 'Donna Nagy', 20, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-B 729', 'ANTITRUST LAW 1', '33722', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 8:30 AM–9:40 AM', 'LW 213', 'Shana Wallace', 21, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Law relating to trade regulation and competitive practices, including antitrust and comparable laws dealing with monopoly, restraint of trade, and unfair methods of competition.', ARRAY[]::TEXT[], NULL),
