    ('LAW-B 764', 'LAW & TECHNOLOGY', '33725', 'Class Status', 'MTuW Monday, Tuesday, Wednesday 1:15 PM–2:10 PM', 'LW 216', 'Fred Cate', 8, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course will explore how digital transformations and other technological innovations are affecting regulation and legal practice. Some possible topics include blockchain and smart contracts, artificial intelligence, biotechnology, data law and policy, and the internet of things.', ARRAY[]::TEXT[], NULL),
