    ('LAW-L 533', 'SEMINAR IN CIVIL PROCEDURE', '34263', 'Class Status', 'Th Thursday 1:15 PM–3:15 PM', 'LW 216', 'Andrew Hammond', 7, NULL, 'Seminar', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This course offers an exploration of state civil procedure that is designed to complement the focus on federal law in the introductory and upper-level civil procedure courses.', ARRAY[]::TEXT[], NULL),
