    ('LAW-L 710', 'SEMINAR IN SOCIETY', '12569', 'Class Status', 'Th Thursday 1:15 PM–3:15 PM', 'HD TBA', 'Victor Quintanilla', 3, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
