    ('LAW-L 713', 'SEMINAR IN LAW AND ECONOMICS', '9665', 'Class Status', 'Tu Tuesday 5:00 PM–7:00 PM', 'LW 216', 'Christopher Ryan', 3, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-L 714', 'SEMINAR ON JUDICIAL CONDUCT', '12570', 'Class Status', 'W Wednesday 3:25 PM–5:25 PM', 'LW 214', 'Charles Geyh', 1, NULL, 'Seminar', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This seminar explores the law governing judicial conduct and the social science research that explains judicial decision-making behavior.', ARRAY[]::TEXT[], NULL),
    ('LAW-L 730', 'SEMINAR IN INTELLECTUAL PROPERTY', '9098', 'Class Status', 'Th Thursday 1:15 PM–3:15 PM', 'LW 120', 'Marshall Leaffer', 8, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This seminar covers intellectual property protection for designs, using it as a vehicle to introduce both the substance of intellectual property regimes and research and writing in the field.', ARRAY[]::TEXT[], NULL),
    ('LAW-L 730', 'SEMINAR IN INTELLECTUAL PROPERTY', '33731', 'Class Status', 'Th Thursday 9:50 AM–11:50 AM', 'LW 222', 'Michael Mattioli', 5, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This seminar covers intellectual property protection for designs, using it as a vehicle to introduce both the substance of intellectual property regimes and research and writing in the field.', ARRAY[]::TEXT[], NULL),
    ('LAW-L 764', 'SEMINAR IN LAW & TECHNOLOGY', '14464', 'Class Status', 'W Wednesday 4:30 PM–6:30 PM', 'LW 203', 'João Marinotti', 2, NULL, 'Seminar', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This seminar will explore how digital transformations and other technological innovations are affecting regulation and legal practice. Some possible topics include blockchain and smart contracts, artificial intelligence, biotechnology, data law and policy, and the internet of things.', ARRAY[]::TEXT[], NULL),
    ('LAW-L 766', 'SEMINAR IN CHILDREN AND THE LAW', '8522', 'Closed', 'Th Thursday 1:15 PM–3:15 PM', 'LW 214', 'Roger Levesque', 0, NULL, 'Seminar', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'Examine the legal construction of childhood from the late nineteenth century to the present. Explore the changing legal context of childhood during these years and topics discussing child custody, tort, juvenile delinquency, disability, child abuse and civic rights. These topics will be examined chronologically as well as in terms of other relevant variables such as race, gender, class and region.', ARRAY[]::TEXT[], NULL),
    ('LAW-L 776', 'SEMINAR IN CRIMINAL LAW', '33732', 'Closed', 'Th Thursday 9:50 AM–11:50 AM', 'LW 216', 'Valena Beety', 0, NULL, 'Lecture', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LAW-L 799', 'SEMINAR IN CONSTITUTIONAL LAW', '15188', 'Class Status', 'Th Thursday 9:50 AM–11:50 AM', 'LW 206E', 'Nicholas Almendares', 2, NULL, 'Seminar', '3', 'LOWELL E. BAIER HALL', ARRAY[]::TEXT[], 'This seminar focuses on different topics in constitutional law.', ARRAY[]::TEXT[], NULL),
    ('LING-G 901', 'ADVANCED RESEARCH', '2072', 'Class Status', NULL, NULL, 'Sandra Kuebler', 18, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours,, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
