    ('LING-L 203', 'INTRODUCTION TO LINGUISTIC ANALYSIS', '5903', 'Class Status', 'MWF Monday, Wednesday, Friday 4:20 PM–5:10 PM', 'BH 307', 'Joel Jenkins', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to basic concepts of linguistic analysis, exemplifying the general principles of structural approaches to the modeling of language. Focus on, and application of, analytical methods applied in phonetics/phonology and morphology/syntax.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 203', 'INTRODUCTION TO LINGUISTIC ANALYSIS', '6570', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 209', 'Kaosarat Aina', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to basic concepts of linguistic analysis, exemplifying the general principles of structural approaches to the modeling of language. Focus on, and application of, analytical methods applied in phonetics/phonology and morphology/syntax.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 203', 'INTRODUCTION TO LINGUISTIC ANALYSIS', '37482', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–3:15 PM', 'BH 123', 'Kenneth De Jong', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to basic concepts of linguistic analysis, exemplifying the general principles of structural approaches to the modeling of language. Focus on, and application of, analytical methods applied in phonetics/phonology and morphology/syntax.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 210', 'TOPICS IN LANGUAGE AND SOCIETY', '29657', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'SB 220', 'Kelly Berkson', 15, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'The study of topics relating to the role of language as a social phenomenon.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LING-L 210', 'TOPICS IN LANGUAGE AND SOCIETY', '29671', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WH 109', 'Nicholas Obeng Agyekum', 15, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'The study of topics relating to the role of language as a social phenomenon.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LING-L 235', 'FOUNDATIONAL SKILLS IN COMPUTATIONAL LINGUISTICS', '12145', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 0119', 'Luke Gessler', 2, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'No previous programming experience required. Introduces basic concepts in programming such as loops or functions with the goal of attaining practical skills for text processing and solving problems in computational linguistics: expression searching, managing text, searching in text, and extracting information from text.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 245', 'LANGUAGE AND COMPUTERS', '10344', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'IF 0119', 'Sandra Kuebler', 8, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Present-day computer systems work with human language. This course surveys issues relating natural language to computers, covers real-world applications, and provides practical experience with natural language on computers. Topics include text encoding, search technology, machine translation, dialogue systems, computer-aided language learning, and the social context of technology.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 306', 'PHONETICS', '4844', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 209', 'Kelly Berkson', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the nature of speech, and the physiology and process of speech production, and training in IPA transcription of utterances drawn from the languages of the world, including various English dialects. The course includes an emphasis on the naturally occurring speech and understanding physical aspects of speech behavior. Some laboratory work is included.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 307', 'PHONOLOGY', '3100', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 237', 'Malgorzata Cavar', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Basic concepts such as phoneme and distinctive feature as defined and used within particular theories. The relationship of phonily to phonetics and morphology; exploration of salient aspects of sound structure and some characteristic modes of argumentation; extensive phonological analysis with some practice in writing phonological rules.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 308', 'MORPHOLOGY', '29658', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 005', 'Emily Hanink', 19, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'An introduction to morphology, the study of the internal structure of words. Topics include the concept of the morpheme, the structure of words and processes of word formation, inflection versus derivation, and issues in morphological theory. Students will do morphological analyses on forms drawn from a variety of languages.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 310', 'SYNTAX', '5152', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HU 217', 'Ann Bunger', 5, NULL, 'Lecture', '3', 'HUTTON HONORS COLLEGE', ARRAY[]::TEXT[], 'Examination of the basic concepts, assumptions, and argumentation of modern syntactic theory to describe and analyze common syntactic structures in English and other languages. Practice in constructing and evaluating grammars.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 315', 'INTRODUCTION TO SOCIOLINGUISTICS', '6070', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'BH 208', 'Amalia Robinson', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the relationship between language and society. Issues include the nature of sociolinguistics; the importance of age, sex, socio-economic status, language ideologies; why people use different dialects/languages in different situations; bilingualism and multilingualism; language choice, language attitudes, language endangerment; the relevance of sociolinguistics to general linguistics theory.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LING-L 325', 'SEMANTICS', '10069', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'BH 144', 'Thomas Grano', 23, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An introduction to the relationship between linguistic forms and their meanings, use and interpretation. Students will investigate the domain of linguistic semantics and acquire the "tools" to do semantic analysis and to critically evaluate those of others.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '2079', 'Class Status', NULL, NULL, 'Ann Bunger', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '5358', 'Class Status', NULL, NULL, 'Francis Tyers', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
