    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '5368', 'Class Status', NULL, NULL, 'Barbara Vance', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '6571', 'Class Status', NULL, NULL, 'Kelly Berkson', 9, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '29741', 'Class Status', NULL, NULL, 'Monica Nesbitt', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '29742', 'Class Status', NULL, NULL, 'Luke Gessler', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 399', 'READINGS IN LINGUISTICS (HONORS)', '29743', 'Class Status', NULL, NULL, 'Shuju Shi', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 415', 'CORPUS LINGUISTICS', '11383', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 229', 'Shobhana Chelliah', 4, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Computer technology has revolutionized the ways linguists approach data. Large bodies of text (corpora) can now be searched to uncover complexities in natural data and explore specific linguistic phenomena. Explores the nature of corpora and programs that annotate or automatically produce a concordance, and how such programs are developed and used.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('LING-L 430', 'LANGUAGE CHANGE AND VARIATION', '34540', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'GA 0013', 'Miriam Shrager', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'An introduction to how languages change over time and how prehistoric languages can be reconstructed by comparing their modern descendants. Major topics include: principles of language change; historical reconstruction; language relatedness and language families; variation and the mechanism of language change; contact-induced change; the birth and death of languages.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('LING-L 431', 'FIELD METHODS', '8365', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 240', 'Samuel Obeng', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to the procedures involved in the structural description of language, using a native speaker of an unfamiliar language whose speech will be analyzed.', ARRAY[]::TEXT[], NULL),
    ('LING-L 485', 'TOPICS IN LINGUISTICS', '34143', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 214', 'Reka Benczes', 16, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in departmental courses.', ARRAY[]::TEXT[], NULL),
    ('LING-L 485', 'TOPICS IN LINGUISTICS', '34144', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–2:15 PM', 'BH 315', 'Reka Benczes', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Studies in special topics not ordinarily covered in departmental courses.', ARRAY[]::TEXT[], NULL),
    ('LING-L 490', 'LINGUISTIC STRUCTURES', '29754', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 231', 'Malgorzata Cavar', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
