    ('LING-L 499', 'HONORS PROJECT', '15351', 'Class Status', NULL, NULL, 'Luke Gessler', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 499', 'HONORS PROJECT', '29745', 'Class Status', NULL, NULL, 'Emily Hanink', 10, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('LING-L 530', 'INTRODUCTION TO HISTORICAL LINGUISTICS', '34541', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'GA 0013', 'Miriam Shrager', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Principles of language classification and subclassification. Processes of diachronic change. Methods of linguistic reconstruction, especially the comparative method and internal reconstruction.', ARRAY[]::TEXT[], NULL),
    ('LING-L 541', 'INTRODUCTORY PHONETICS', '12021', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'LH 130', 'Kenneth De Jong', 34, 'Lecture', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of speech sound types in languages of the world with practice in discrimination, transcription, and production. Introduction to acoustic phonetics, physiology of speech production, and speech perception with concurrent laboratory section.', ARRAY[]::TEXT[], NULL),
    ('LING-L 541', 'INTRODUCTORY PHONETICS', '12022', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'LH 016', 'Staff', 11, 'Laboratory', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of speech sound types in languages of the world with practice in discrimination, transcription, and production. Introduction to acoustic phonetics, physiology of speech production, and speech perception with concurrent laboratory section.', ARRAY[]::TEXT[], NULL),
    ('LING-L 541', 'INTRODUCTORY PHONETICS', '12023', 'Class Status', 'Th Thursday 2:20 PM–3:35 PM', 'BH 135', 'Staff', 8, 'Laboratory', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of speech sound types in languages of the world with practice in discrimination, transcription, and production. Introduction to acoustic phonetics, physiology of speech production, and speech perception with concurrent laboratory section.', ARRAY[]::TEXT[], NULL),
    ('LING-L 541', 'INTRODUCTORY PHONETICS', '12024', 'Class Status', 'Th Thursday 3:55 PM–5:10 PM', 'BH 317', 'Staff', 15, 'Laboratory', 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Survey of speech sound types in languages of the world with practice in discrimination, transcription, and production. Introduction to acoustic phonetics, physiology of speech production, and speech perception with concurrent laboratory section.', ARRAY[]::TEXT[], NULL),
    ('LING-L 543', 'SYNTACTIC ANALYSIS', '2083', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 015', 'Emily Hanink', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'An examination of the methods and argumentation used in syntactic analysis conducted within the framework of generative grammar. Emphasis on structuring and evaluating grammatical analyses and promoting critical understanding of the generative framework.', ARRAY[]::TEXT[], NULL),
    ('LING-L 545', 'COMPUTATION AND LINGUISTIC ANALYSIS', '8872', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'IF 0119', 'Shuju Shi', 10, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to current semantic theory, its tools, concepts, and principles. Emphasis on constructing detailed fragments of natural language with syntactic and semantic components.', ARRAY[]::TEXT[], NULL),
    ('LING-L 555', 'PROGRAMMING FOR COMPUTATIONAL LANGUAGE', '4283', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'IF 0119', 'Luke Gessler', 6, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'This course will introduce the fundamentals of programming and computer science, aiming at attaining practical skills for text processing. Through lectures, lab sessions, and weekly or bi-weekly assignments, students will learn the essentials of a given programming language (e.g., Perl) and how to apply these skills to natural language data.', ARRAY[]::TEXT[], NULL),
    ('LING-L 590', 'LINGUISTIC STRUCTURE', '29755', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 231', 'Malgorzata Cavar', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Analysis of particular aspects of the structure of a language or of a group of closely related languages. Methods used may include text analysis, informant work, study of secondary sources, lectures, reports.', ARRAY[]::TEXT[], NULL),
    ('LING-L 615', 'CORPUS LINGUISTICS', '6182', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 229', 'Shobhana Chelliah', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Advances in computer technology have revolutionized the ways linguists can approach their data. By using computers, we can access large bodies of text (corpora) and search for phenomena. The course will give an introduction to the methodology and applications in the field.', ARRAY[]::TEXT[], NULL),
    ('LING-L 635', 'APPLICATIONS OF SPEECH PROCESSING', '33970', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'FA 004', 'Shuju Shi', 12, NULL, 'Lecture', '3', 'FINE ARTS', ARRAY[]::TEXT[], 'This course explores advanced topics and current trends in speech processing, focusing on applications in areas such as speech recognition, synthesis, and speech enhancement. The course will cover both theoretical foundations and practical implementation aspects, including recent advances in machine learning and deep learning as applied to speech processing.', ARRAY[]::TEXT[], NULL),
    ('LING-L 636', 'PIDGINS AND CREOLES', '29951', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SY 200', 'Kevin Rottet', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Survey of the field of pidgin and creole linguistics; presentational of the structure of selected prototypical pidgins and creoles; review of the theories for the genesis of creoles and their relationship to current issues in language acquisition and historical linguistics; discussion of language planning issues specific to pidgins and creoles, as well as discussion of current issues.', ARRAY[]::TEXT[], NULL),
    ('LING-L 645', 'ADVANCED NATURAL LANGUAGE PROCESSING', '3253', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'IF 0119', 'Damir Cavar', 5, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'An introduction to statistical models and machine learning paradigms in NLP. Covers basic notions in probability and information theory, focusing on the concepts needed for NLP, including Markov Models. Additional topics may include word sense disambiguation, text categorization, and statistical alignment methods and their use in machine translation.', ARRAY[]::TEXT[], NULL),
    ('LING-L 646', 'ADVANCED SEMANTICS', '29659', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 313', 'Thomas Grano', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Focus on advanced topics in the principles of compositional interpretation and their use in analyzing truth-conditional aspects of natural language phrases and sentences. Specific topics may include event semantics, tense, and aspect; modality; nominal and pronominal expressions; questions; and cross-linguistic semantics.', ARRAY[]::TEXT[], NULL),
    ('LING-L 653', 'FIELD METHODS IN LINGUISTICS 1', '11100', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'BH 240', 'Samuel Obeng', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Techniques of data collection and analysis based on work with a native speaker of a language unknown to the students.', ARRAY[]::TEXT[], NULL),
    ('LING-L 665', 'APPLYING MACHINE LEARNING TECHNIQUES IN COMPUTATIONAL LINGUISTICS', '12087', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'IF 0119', 'Luke Gessler', 7, NULL, 'Lecture', '3', 'LUDDY HALL', ARRAY[]::TEXT[], 'Introduction to major algorithms in Machine Learning (ML) as well as applications of these techniques to a wide range of CL topics. Course includes an introduction to CL and to W focused on supervised algorithms: decision trees and rule learning. Also considered are applications of ML algorithms to CL problems.', ARRAY[]::TEXT[], NULL),
    ('LING-L 690', 'ADVANCED READINGS IN LINGUISTICS', '2084', 'Class Status', NULL, NULL, 'Ann Bunger', 10, NULL, 'Readings', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
